input.command:
kubectl exec -n mongodb mongodb-replica-1 -- mongosh --quiet \
  "mongodb://admin-user:admin123password@localhost:27017/admin" \
  --eval '
// Step 1: Create reportingRole in appdb
db.getSiblingDB("appdb").createRole({
  role: "reportingRole",
  privileges: [
    {
      resource: { db: "appdb", collection: "reports" },
      actions: ["find", "aggregate", "collStats", "listIndexes"]
    }
  ],
  roles: []
});
print("reportingRole created");

// Step 2: Create app-user with readWrite on appdb
db.createUser({
  user: "app-user",
  pwd: "app123password",
  roles: [{ role: "readWrite", db: "appdb" }]
});
print("app-user created");

// Step 3: Grant reportingRole to readonly-user (already has read on appdb)
db.grantRolesToUser("readonly-user", [
  { role: "reportingRole", db: "appdb" }
]);
print("reportingRole granted to readonly-user");
' 2>/dev/null

