cat <<'FUNCTEST' > /tmp/mongo_functest.js
// Test 1: app-user can readWrite on appdb
print("=== Test: app-user readWrite on appdb ===");
try {
  var appConn = new Mongo("mongodb://app-user:app123password@localhost:27017/appdb");
  var appDb = appConn.getDB("appdb");
  appDb.testcol.insertOne({test: "value"});
  var found = appDb.testcol.findOne({test: "value"});
  print("PASS: app-user insert+find: " + (found ? "ok" : "missing"));
  appDb.testcol.deleteOne({test: "value"});
  print("PASS: app-user delete: ok");
} catch(e) { print("FAIL: " + e.message); }

// Test 2: readonly-user can read on appdb
print("\n=== Test: readonly-user read on appdb ===");
try {
  var roConn = new Mongo("mongodb://readonly-user:readonly123password@localhost:27017/appdb");
  var roDb = roConn.getDB("appdb");
  var count = roDb.testcol.countDocuments();
  print("PASS: readonly-user find/count: " + count);
} catch(e) { print("FAIL: " + e.message); }

// Test 3: readonly-user cannot write on appdb
print("\n=== Test: readonly-user cannot write on appdb ===");
try {
  var roConn2 = new Mongo("mongodb://readonly-user:readonly123password@localhost:27017/appdb");
  var roDb2 = roConn2.getDB("appdb");
  roDb2.testcol.insertOne({bad: "write"});
  print("FAIL: should have been denied");
} catch(e) { print("PASS: write correctly denied: " + e.message.substring(0,60)); }

// Test 4: readonly-user can aggregate on appdb.reports
print("\n=== Test: readonly-user aggregate on appdb.reports ===");
try {
  var roConn3 = new Mongo("mongodb://readonly-user:readonly123password@localhost:27017/appdb");
  var roDb3 = roConn3.getDB("appdb");
  // seed a doc so aggregate returns something
  var adminDb = db.getSiblingDB("appdb");
  adminDb.reports.insertOne({report: "q1", val: 100});
  var result = roDb3.reports.aggregate([{$match: {}}, {$count: "total"}]).toArray();
  print("PASS: aggregate on appdb.reports succeeded, result: " + JSON.stringify(result));
  adminDb.reports.deleteOne({report: "q1"});
} catch(e) { print("FAIL: " + e.message); }

// Test 5: admin-user still works
print("\n=== Test: admin-user access ===");
try {
  var pong = db.adminCommand({ping: 1});
  print("PASS: admin-user ping: " + pong.ok);
} catch(e) { print("FAIL: " + e.message); }
FUNCTEST
kubectl cp /tmp/mongo_functest.js mongodb/mongodb-replica-1:/tmp/mongo_functest.js
